const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'YOUR_REDIRECT_URI';
const authUrl = 'https://provider.com/oauth2/authorize';
const apiUrl = 'https://api.provider.com/resource';
let accessToken = null;

function redirectToAuth() {
    const url = `${authUrl}?response_type=token&client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUri)}`;
    window.location.href = url;
}

function parseAccessToken() {
    const hash = window.location.hash;
    if (hash) {
        const params = new URLSearchParams(hash.substring(1));
        accessToken = params.get('access_token');
        if (accessToken) {
            sessionStorage.setItem('access_token', accessToken);
            window.location.hash = ''; // Clear the hash
        }
    } else {
        accessToken = sessionStorage.getItem('access_token');
    }
}

function fetchProtectedResource() {
    if (!accessToken) {
        console.warn('Access token not available');
        return;
    }
    
    fetch(apiUrl, {
        method: 'GET',
        headers: {
            'Authorization': `Bearer ${accessToken}`
        }
    })
    .then(response => {
        if (!response.ok) {
            throw new Error('Network response was not ok ' + response.statusText);
        }
        return response.json();
    })
    .then(data => {
        console.log('Protected data:', data);
    })
    .catch(error => {
        console.error('Error fetching protected resource:', error);
    });
}

// Check for access token on page load
document.addEventListener('DOMContentLoaded', () => {
    parseAccessToken();
    if (accessToken) {
        fetchProtectedResource();
    } else {
        redirectToAuth();
    }
});